inline {1} ^r<@.
swap {1} ^pk0<- -3. swap {1} ^c0<- & +1 @^pk0<- & +1.
sim.
call (: true); wp.
conseq (: ={k1, k0, pk, sk, m1, m0, glob E_s, glob A}
       /\ c{1} = kc{2})=> //.
by sim.
qed.

