          = Pr[DEM_PAS_Exp(E_s, B_s(E_kem, A)).run(true) @ &m: res].
byequiv=> //; proc.
swap {2} ^k<$ 1.
inline {2} ^r<@.
swap {2} ^c0<- & +1 -3.
inline {2} 1.
by sim.
qed.

local lemma Hop3 &m:
  `| Pr[PKE_CPA_Exp(KEMDEM(E_kem, E_s), A).run(true) @ &m: res]
   - Pr[Game1.run(true) @ &m: res] |
