  proc run(b : bool) = {
    var pk, sk, m0, m1, k0, k1, kc, c, r;

    (pk, sk) <@ E_kem.keygen();
    (m0, m1) <@ A.choose(pk);
    (k0, kc) <@ E_kem.enc(pk);
    k1 <$ dkey;
    c <@ E_s.enc(k1, if b then m1 else m0);
