  inline {2} 1.
  by sim.
have -> //: Pr[Game1.run(true) @ &m: res]
          = Pr[DEM_PAS_Exp(E_s, B_s(E_kem, A)).run(true) @ &m: res].
byequiv=> //; proc.
swap {2} ^k<$ 1.
inline {2} ^r<@.
swap {2} ^c0<- & +1 -3.
inline {2} 1.
by sim.
qed.

