    - Pr[KEM_CPA_Exp(E_kem, B_kem_1(E_s, A)).run(false) @ &m: res] |.
proof.
have ->: Pr[PKE_CPA_Exp(KEMDEM(E_kem, E_s), A).run(true) @ &m: res]
       = Pr[KEM_CPA_Exp(E_kem, B_kem_1(E_s, A)).run(false) @ &m: res].
+ byequiv=> //; proc.
  inline *.
  swap {1} ^pk0<- -1. swap {1} 5 -2.
  wp; call (: true).
  wp; call (: true).
  wp; call (: true).
  wp; rnd {2}; call (: true).
